from fastapi import FastAPI, Depends, HTTPException, status
from fastapi.security import APIKeyHeader

# Bu, gerçek bir uygulamada veritabanından veya çevre değişkenlerinden alınmalıdır.
# Örnek olarak sabit bir liste kullanılmıştır.
API_KEYS = [
    "mysecretapikey123",
    "anothersecurekey456"
]

api_key_header = APIKeyHeader(name="X-API-Key", auto_error=False)

async def get_api_key(api_key: str = Depends(api_key_header)):
    if api_key is None:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="API Key missing",
            headers={"WWW-Authenticate": "X-API-Key"},
        )
    if api_key not in API_KEYS:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid API Key",
            headers={"WWW-Authenticate": "X-API-Key"},
        )
    return api_key

app = FastAPI()

@app.get("/")
async def read_root():
    return {"message": "Welcome to the unauthenticated root!"}

@app.get("/protected-route")
async def read_protected_route(api_key: str = Depends(get_api_key)):
    return {"message": "You have successfully accessed the protected route!", "authenticated_key": api_key}

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)
